import java.io.*;
import java.util.*;

import org.apache.commons.text.StringEscapeUtils;

public class XSSFixedCode {

    public static void main(String[] args) {
        Scanner scanner = new Scanner(System.in);

        System.out.print("Enter your name: ");
        String userInput = scanner.nextLine();

        // Sanitize user input to prevent XSS attacks
        String sanitizedUserInput = StringEscapeUtils.escapeHtml4(userInput);

        // Build safe greeting message
        String greetingMessage = "Hello, " + sanitizedUserInput + "! Welcome to our website!";

        // Render HTML response with safe user input
        System.out.println("<html><body>");
        System.out.println("<h1>" + greetingMessage + "</h1>");
        System.out.println("</body></html>");
    }
}

### Explanation:
취약유형: Cross-Site Scripting (XSS)
